    {
        $this->excludeList           = new ExcludeList;
        $this->identifyIssueTrigger  = $identifyIssueTrigger;
        $this->issueTriggerResolvers = [new DefaultIssueTriggerResolver];
    }

public static function expandIniShorthandBytes($val)
    {
        if (!\is_string($val)) {
            return false;
        }

        // support -1
        if ((int) $val < 0) {
            return (int) $val;
        }

        if (!(bool) preg_match('/^\s*(?<val>\d+)(?:\.\d+)?\s*(?<unit>[gmk]?)\s*$/i', $val, $match)) {
            return false;
        }

        $val = (int) $match['val'];
        switch (strtolower($match['unit'])) {
            case 'g':
                $val *= 1024;
                // no break
            case 'm':
                $val *= 1024;
                // no break
            case 'k':
                $val *= 1024;
        }

        return $val;
    }

protected function normalizeException(\Throwable $e, int $depth = 0): string
    {
        $str = $this->formatException($e);

        $previous = $e->getPrevious();
        while ($previous instanceof \Throwable) {
            $depth++;
            if ($depth > $this->maxNormalizeDepth) {
                $str .= "\n[previous exception] Over " . $this->maxNormalizeDepth . ' levels deep, aborting normalization';
                break;
            }
            $str .= "\n[previous exception] " . $this->formatException($previous);
            $previous = $previous->getPrevious();
        }

        return $str;
    }

public function validateInContext(mixed $value, Constraint $constraint, ExecutionContextInterface $context): void
    {
        $oldContext = $this->context ?? null;

        try {
            $this->context = $context;
            if (self::overridesInitialize(static::class)) {
                trigger_deprecation('symfony/validator', '8.1', \sprintf('Overriding "%s::initialize()" in "%s" is deprecated. Put the additional logic in the "validate()" method instead.', self::class, static::class));
                $this->initialize($context);
            }
            $this->validate($value, $constraint);
        } finally {
            if (null !== $oldContext) {
                $this->context = $oldContext;
            } else {
                unset($this->context);
            }
        }
    }

public function move(string $source, string $destination, Config $config): void
    {
        $sourcePath = $this->prefixer->prefixPath($source);
        $destinationPath = $this->prefixer->prefixPath($destination);

        $this->ensureRootDirectoryExists();
        $this->ensureDirectoryExists(
            dirname($destinationPath),
            $this->resolveDirectoryVisibility($config->get(Config::OPTION_DIRECTORY_VISIBILITY))
        );

        error_clear_last();
        if ( ! @rename($sourcePath, $destinationPath)) {
            throw UnableToMoveFile::because(error_get_last()['message'] ?? 'unknown reason', $source, $destination);
        }

        if ($visibility = $config->get(Config::OPTION_VISIBILITY)) {
            $this->setVisibility($destination, (string) $visibility);
        }
    }

public function checksum(string $path, array $config = []): string
    {
        $config = $this->config->extend($config);

        if ( ! $this->adapter instanceof ChecksumProvider) {
            return $this->calculateChecksumFromStream($path, $config);
        }

        try {
            return $this->adapter->checksum(
                $this->pathNormalizer->normalizePath($path),
                $config,
            );
        } catch (ChecksumAlgoIsNotSupported) {
            return $this->calculateChecksumFromStream(
                $this->pathNormalizer->normalizePath($path),
                $config,
            );
        }
    }

private function writeToFile(string $path, $contents, Config $config): void
    {
        $prefixedLocation = $this->prefixer->prefixPath($path);
        $this->ensureRootDirectoryExists();
        $this->ensureDirectoryExists(
            dirname($prefixedLocation),
            $this->resolveDirectoryVisibility($config->get(Config::OPTION_DIRECTORY_VISIBILITY))
        );
        error_clear_last();

        if (@file_put_contents($prefixedLocation, $contents, $this->writeFlags) === false) {
            throw UnableToWriteFile::atLocation($path, error_get_last()['message'] ?? '');
        }

        if ($visibility = $config->get(Config::OPTION_VISIBILITY)) {
            $this->setVisibility($path, (string) $visibility);
        }
    }

private function mapS3ObjectMetadata(array $metadata, string $path): StorageAttributes
    {
        if (substr($path, -1) === '/') {
            return new DirectoryAttributes(rtrim($path, '/'));
        }

        $mimetype = $metadata['ContentType'] ?? null;
        $fileSize = $metadata['ContentLength'] ?? $metadata['Size'] ?? null;
        $fileSize = $fileSize === null ? null : (int) $fileSize;
        $dateTime = $metadata['LastModified'] ?? null;
        $lastModified = $dateTime instanceof DateTimeResult ? $dateTime->getTimeStamp() : null;

        return new FileAttributes(
            $path,
            $fileSize,
            null,
            $lastModified,
            $mimetype,
            $this->extractExtraMetadata($metadata)
        );
    }

public function copy(string $source, string $destination, Config $config): void
    {
        $source = $this->preparePath($source);
        $destination = $this->preparePath($destination);

        if ( ! $this->fileExists($source)) {
            throw UnableToCopyFile::fromLocationTo($source, $destination);
        }

        $lastModified = $config->get('timestamp', time());
        $this->files[$destination] = $this->files[$source]->withLastModified($lastModified);

        if ($visibility = $config->get(Config::OPTION_VISIBILITY)) {
            $this->setVisibility($destination, $visibility);
        }
    }

private static function assertCustomListNameAllowed(string $listName): void
    {
        if (in_array($listName, self::RESERVED_NAMES, true)) {
            throw new \UnexpectedValueException(sprintf(
                'Invalid custom dependency policy name "%s": this name is reserved for a built-in dependency policy.',
                $listName
            ));
        }

        $error = self::getFutureReservedListNameError($listName);
        if ($error !== null) {
            throw new \UnexpectedValueException('Invalid custom dependency policy name: '.$error);
        }
    }

public function connect(
    #[SensitiveParameter]
    array $params,
): Connection {
    $isMemory = $params['memory'] ?? false;

    if (isset($params['path'])) {
        if ($isMemory) {
            throw new Exception(
                'Invalid connection settings: specifying both parameters "path" and "memory" is ambiguous.',
            );
        }

        $filename = $params['path'];
    } elseif ($isMemory) {
        $filename = ':memory:';
    } else {
        throw new Exception(
            'Invalid connection settings: specify either the "path" or the "memory" parameter for SQLite3.',
        );
    }

    try {
        $connection = new SQLite3($filename);
    } catch (\Exception $e) {
        throw Exception::new($e);
    }

    $connection->enableExceptions(true);

    return new Connection($connection);
}

public function hasStaticProperty(string $propertyName): bool
	{
		if (array_key_exists($propertyName, $this->hasStaticPropertyCache)) {
			return $this->hasStaticPropertyCache[$propertyName];
		}

		$phpClassReflectionExtension = $this->classReflectionExtensionRegistryProvider->getRegistry()->getPhpClassReflectionExtension();
		if ($phpClassReflectionExtension->hasProperty($this, $propertyName)) {
			$property = $phpClassReflectionExtension->getNativeProperty($this, $propertyName);
			if ($property->isStatic()) {
				return $this->hasStaticPropertyCache[$propertyName] = true;
			}
		}

		if ($this->classReflectionExtensionRegistryProvider->getRegistry()->getRequireExtendsPropertyClassReflectionExtension()->hasStaticProperty($this, $propertyName)) {
			return $this->hasStaticPropertyCache[$propertyName] = true;
		}

		return $this->hasStaticPropertyCache[$propertyName] = false;
	}

public function processNode(Node $node, Scope $scope): array
	{
		if (count($node->getTryCatchExitPoints()) === 0) {
			return [];
		}

		$errors = [];
		foreach ($node->getTryCatchExitPoints() as $exitPoint) {
			$errors[] = RuleErrorBuilder::message(sprintf('This %s is overwritten by a different one in the finally block below.', $this->describeExitPoint($exitPoint->getStatement())))
				->line($exitPoint->getStatement()->getStartLine())
				->identifier('finally.exitPoint')
				->build();
		}

		foreach ($node->getFinallyExitPoints() as $exitPoint) {
			$errors[] = RuleErrorBuilder::message(sprintf('The overwriting %s is on this line.', $this->describeExitPoint($exitPoint->getStatement())))
				->line($exitPoint->getStatement()->getStartLine())
				->identifier('finally.exitPoint')
				->build();
		}

		return $errors;
	}

public function handle(ServerRequestInterface $request): ResponseInterface
    {
        if ($this->callableResolver instanceof AdvancedCallableResolverInterface) {
            $callable = $this->callableResolver->resolveRoute($this->callable);
        } else {
            $callable = $this->callableResolver->resolve($this->callable);
        }
        $strategy = $this->invocationStrategy;

        $strategyImplements = class_implements($strategy);

        if (
            is_array($callable)
            && $callable[0] instanceof RequestHandlerInterface
            && !in_array(RequestHandlerInvocationStrategyInterface::class, $strategyImplements)
        ) {
            $strategy = new RequestHandler();
        }

        $response = $this->responseFactory->createResponse();
        return $strategy($callable, $request, $response, $this->arguments);
    }

private function createContainerLoader(ContainerBuilder $container, ?string $env, bool $prepend): DelegatingLoader
    {
        $locator = new FileLocator();
        $resolver = new LoaderResolver([
            new YamlFileLoader($container, $locator, $env, $prepend),
            new IniFileLoader($container, $locator, $env),
            new PhpFileLoader($container, $locator, $env, $prepend),
            new GlobFileLoader($container, $locator, $env),
            new DirectoryLoader($container, $locator, $env),
            new ClosureLoader($container, $env),
        ]);

        return new DelegatingLoader($resolver);
    }

protected function getContainerLoader(ContainerInterface $container): DelegatingLoader
    {
        $env = $this->getEnvironment();
        $locator = new FileLocator($this);
        $resolver = new LoaderResolver([
            new YamlFileLoader($container, $locator, $env),
            new IniFileLoader($container, $locator, $env),
            new PhpFileLoader($container, $locator, $env),
            new GlobFileLoader($container, $locator, $env),
            new DirectoryLoader($container, $locator, $env),
            new ClosureLoader($container, $env),
        ]);

        return new DelegatingLoader($resolver);
    }

public function configureOptions(OptionsResolver $resolver): void
    {
        parent::configureOptions($resolver);

        // Constraint should always be converted to an array
        $constraintsNormalizer = static fn (Options $options, $constraints) => \is_object($constraints) ? [$constraints] : (array) $constraints;

        $resolver->setDefaults([
            'error_mapping' => [],
            'constraints' => [],
            'invalid_message' => 'This value is not valid.',
            'invalid_message_parameters' => [],
            'allow_extra_fields' => false,
            'extra_fields_message' => 'This form should not contain extra fields.',
        ]);
        $resolver->setAllowedTypes('constraints', [Constraint::class, Constraint::class.'[]']);
        $resolver->setNormalizer('constraints', $constraintsNormalizer);
    }

public function addRepository(RepositoryInterface $repository): void
    {
        if (
            $repository instanceof LockArrayRepository
            || $repository instanceof InstalledRepositoryInterface
            || $repository instanceof RootPackageRepository
            || $repository instanceof PlatformRepository
        ) {
            parent::addRepository($repository);

            return;
        }

        throw new \LogicException('An InstalledRepository can not contain a repository of type '.get_class($repository).' ('.$repository->getRepoName().')');
    }

public function getInstanceProperty(ClassReflection $classReflection, string $propertyName): ExtendedPropertyReflection
	{
		$property = $this->findProperty(
			$classReflection,
			$propertyName,
			static fn (Type $type, string $propertyName): TrinaryLogic => $type->hasInstanceProperty($propertyName),
			static fn (Type $type, string $propertyName): ExtendedPropertyReflection => $type->getInstanceProperty($propertyName, new OutOfClassScope()),
		);
		if ($property === null) {
			throw new ShouldNotHappenException();
		}

		return $property;
	}

private function getAnalyser(DirectRuleRegistry $ruleRegistry): Analyser
	{
		if ($this->analyser === null) {
			$collectorRegistry = new CollectorRegistry($this->getCollectors());

			$nodeScopeResolver = $this->createNodeScopeResolver();

			$fileAnalyser = new FileAnalyser(
				self::createScopeFactory(
					$this->createReflectionProvider(),
					$this->getTypeSpecifier(),
				),
				$nodeScopeResolver,
				$this->getParser(),
				self::getContainer()->getByType(DependencyResolver::class),
				new IgnoreErrorExtensionProvider(self::getContainer()),
				self::getContainer()->getByType(RuleErrorTransformer::class),
				new LocalIgnoresProcessor(),
				false,
			);
			$this->analyser = new Analyser(
				$fileAnalyser,
				$ruleRegistry,
				$collectorRegistry,
				$nodeScopeResolver,
				50,
			);
		}

		return $this->analyser;
	}

public function __construct(
    string $webhookUrl,
    ?string $channel = null,
    ?string $username = null,
    bool $useAttachment = true,
    ?string $iconEmoji = null,
    bool $useShortAttachment = false,
    bool $includeContextAndExtra = false,
    $level = Level::Critical,
    bool $bubble = true,
    array $excludeFields = []
) {
    if (!\extension_loaded('curl')) {
        throw new MissingExtensionException('The curl extension is needed to use the SlackWebhookHandler');
    }

    parent::__construct($level, $bubble);

    $this->webhookUrl = $webhookUrl;

    $this->slackRecord = new SlackRecord(
        $channel,
        $username,
        $useAttachment,
        $iconEmoji,
        $useShortAttachment,
        $includeContextAndExtra,
        $excludeFields
    );
}

public static function getErrorMessage(string $extensionName, ?string $loadingFilePath, string $namespaceOrAlias, array $foundExtensionNamespaces): string
    {
        $message = '';
        if (isset(self::BUNDLE_EXTENSIONS[$extensionName])) {
            $message .= \sprintf('Did you forget to install or enable the %s? ', self::BUNDLE_EXTENSIONS[$extensionName]);
        }

        $message .= match (true) {
            \is_string($loadingFilePath) => \sprintf('There is no extension able to load the configuration for "%s" (in "%s"). ', $extensionName, $loadingFilePath),
            default => \sprintf('There is no extension able to load the configuration for "%s". ', $extensionName),
        };

        return $message.\sprintf('Looked for namespace "%s", found "%s".', $namespaceOrAlias, $foundExtensionNamespaces ? implode('", "', $foundExtensionNamespaces) : 'none');
    }

public function matchesPath(string $requestPath): bool
    {
        $cookiePath = $this->getPath();

        // Match on exact matches or when path is the default empty "/"
        if ($cookiePath === '/' || $cookiePath == $requestPath) {
            return true;
        }

        // Ensure that the cookie-path is a prefix of the request path.
        if (0 !== \strpos($requestPath, $cookiePath)) {
            return false;
        }

        // Match if the last character of the cookie-path is "/"
        if (\substr($cookiePath, -1, 1) === '/') {
            return true;
        }

        // Match if the first character not included in cookie path is "/"
        return \substr($requestPath, \strlen($cookiePath), 1) === '/';
    }

public function disconnect()
    {
        // If could not connect at all, no need to disconnect
        if ($this->pop_conn === false) {
            return;
        }

        $this->sendString('QUIT' . static::LE);

        // RFC 1939 shows POP3 server sending a +OK response to the QUIT command.
        // Try to get it.  Ignore any failures here.
        try {
            $this->getResponse();
        } catch (Exception $e) {
            //Do nothing
        }

        //The QUIT command may cause the daemon to exit, which will kill our connection
        //So ignore errors here
        try {
            @fclose($this->pop_conn);
        } catch (Exception $e) {
            //Do nothing
        }

        // Clean up attributes.
        $this->connected = false;
        $this->pop_conn  = false;
    }

public function move(string $source, string $destination, array $config = []): void
    {
        $config = $this->resolveConfigForMoveAndCopy($config);
        $from = $this->pathNormalizer->normalizePath($source);
        $to = $this->pathNormalizer->normalizePath($destination);

        if ($from === $to) {
            $resolutionStrategy = $config->get(Config::OPTION_MOVE_IDENTICAL_PATH, ResolveIdenticalPathConflict::TRY);

            if ($resolutionStrategy === ResolveIdenticalPathConflict::FAIL) {
                throw UnableToMoveFile::sourceAndDestinationAreTheSame($source, $destination);
            } elseif ($resolutionStrategy === ResolveIdenticalPathConflict::IGNORE) {
                return;
            }
        }

        $this->adapter->move($from, $to, $config);
    }

private function createExtensionHint(array $missingExtensions): string
    {
        $paths = IniHelper::getAll();

        if ('' === $paths[0]) {
            if (count($paths) === 1) {
                return '';
            }

            array_shift($paths);
        }

        $ignoreExtensionsArguments = implode(" ", array_map(static function ($extension) {
            return "--ignore-platform-req=$extension";
        }, array_unique($missingExtensions)));

        $text = "To enable extensions, verify that they are enabled in your .ini files:\n    - ";
        $text .= implode("\n    - ", $paths);
        $text .= "\nYou can also run `php --ini` in a terminal to see which files are used by PHP in CLI mode.";
        $text .= "\nAlternatively, you can run Composer with `$ignoreExtensionsArguments` to temporarily ignore these required extensions.";

        return $text;
    }

private function getDynamicFunctionReturnType(MutatingScope $scope, FuncCall $normalizedNode, FunctionReflection $functionReflection): ?Type
	{
		foreach ($this->dynamicReturnTypeExtensionRegistryProvider->getRegistry()->getDynamicFunctionReturnTypeExtensions($functionReflection) as $dynamicFunctionReturnTypeExtension) {
			$resolvedType = $dynamicFunctionReturnTypeExtension->getTypeFromFunctionCall(
				$functionReflection,
				$normalizedNode,
				$scope,
			);

			if ($resolvedType !== null) {
				return $resolvedType;
			}
		}

		return null;
	}

private static function overrideAcceptorParameters(ParametersAcceptor $acceptor, array $parameters): ParametersAcceptor
	{
		if ($acceptor instanceof ExtendedParametersAcceptor) {
			return new ExtendedFunctionVariant(
				$acceptor->getTemplateTypeMap(),
				$acceptor->getResolvedTemplateTypeMap(),
				array_map(static fn (ParameterReflection $p): ExtendedParameterReflection => $p instanceof ExtendedParameterReflection ? $p : self::wrapParameter($p), $parameters),
				$acceptor->isVariadic(),
				$acceptor->getReturnType(),
				$acceptor->getPhpDocReturnType(),
				$acceptor->getNativeReturnType(),
				$acceptor->getCallSiteVarianceMap(),
			);
		}

		return new FunctionVariant(
			$acceptor->getTemplateTypeMap(),
			$acceptor->getResolvedTemplateTypeMap(),
			$parameters,
			$acceptor->isVariadic(),
			$acceptor->getReturnType(),
			TemplateTypeVarianceMap::createEmpty(),
		);
	}

public function pushInFunctionCall($reflection, ?ParameterReflection $parameter, bool $rememberTypes): self
	{
		$stack = $this->inFunctionCallsStack;
		$stack[] = [$reflection, $parameter];

		$functionScope = $this->scopeFactory->create(
			$this->context,
			$this->isDeclareStrictTypes(),
			$this->getFunction(),
			$this->getNamespace(),
			$this->expressionTypes,
			$this->nativeExpressionTypes,
			$this->conditionalExpressions,
			$this->inClosureBindScopeClasses,
			$this->anonymousFunctionReflection,
			$this->isInFirstLevelStatement(),
			$this->currentlyAssignedExpressions,
			$this->currentlyAllowedUndefinedExpressions,
			$stack,
			$this->afterExtractCall,
			$this->parentScope,
			$this->nativeTypesPromoted,
		);

		if ($rememberTypes) {
			$functionScope->resolvedTypes = $this->resolvedTypes;
		}

		return $functionScope;
	}
